// Parse incoming missing secrets list (webhook body: { missing: [...] }).
const input = $input.first().json;
const body = input.body || input;
const missing = body.missing || body.all_missing || input.missing || input.all_missing || [];

// Classify each secret as auto-provisionable or manual.
const AUTO_PROVISION = {
  // Secrets that COULD be auto-provisioned with a bootstrap token.
  // For now these are stubs — real implementation would call provider APIs.
  'CLOUDFLARE_API_TOKEN': { provider: 'cloudflare', method: 'api_token_create', auto: false, reason: 'Requires Cloudflare dashboard or bootstrap Global API Key' },
  'FIRECRAWL_API_KEY': { provider: 'firecrawl', method: 'manual', auto: false, reason: 'Sign up at firecrawl.dev and copy API key' }
};

const ALWAYS_MANUAL = [
  'N8N_API_KEY', 'N8N_ENCRYPTION_KEY', 'SUPABASE_SERVICE_ROLE_KEY',
  'ANTHROPIC_API_KEY', 'OPENAI_API_KEY', 'MONDAY_API_TOKEN',
  'COMMANDER_WEBHOOK_TOKEN', 'VAULT_MASTER_KEY', 'GRAFANA_PASSWORD'
];

const provisioned = [];
const manual = [];
const errors = [];

for (const name of missing) {
  const info = AUTO_PROVISION[name];
  if (info && info.auto) {
    // Stub: attempt auto-provision
    try {
      // In a real implementation, call the provider API here.
      // e.g. Cloudflare: POST /client/v4/user/tokens with bootstrap token
      provisioned.push({ name, method: info.method, provider: info.provider });
    } catch (e) {
      errors.push({ name, error: e.message });
    }
  } else {
    const reason = info ? info.reason : 'Manual provisioning required — see docs/runbooks/missing-secrets.md';
    manual.push({ name, reason });
  }
}

return [{ json: { provisioned, manual, errors, total_missing: missing.length } }];

// Store any auto-provisioned secrets into the vault adapter.
const report = $input.first().json;
const vaultBase = process.env.VAULT_BASE_URL || 'http://localhost:4000';

for (const item of report.provisioned) {
  if (item.value) {
    try {
      await fetch(`${vaultBase}/secret/${item.name}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ value: item.value })
      });
      item.stored_in = 'vault';
    } catch (e) {
      report.errors.push({ name: item.name, error: `Vault store failed: ${e.message}` });
    }
    delete item.value; // never pass value downstream
  }
}

return [{ json: report }];

// Build human-readable request packages for manual secrets.
const report = $input.first().json;

const packages = report.manual.map(item => ({
  secret_name: item.name,
  action_required: item.reason,
  runbook: 'https://github.com/<owner>/<repo>/blob/main/docs/runbooks/missing-secrets.md',
  instructions: [
    `1. Obtain the value for ${item.name} from the appropriate provider.`,
    `2. Store it: set in server ENV or run: echo <value> | vaultctl set ${item.name}`,
    `3. Re-run secrets:heal to verify.`
  ]
}));

return [{ json: { ...report, request_packages: packages } }];

// Final provisioner report. Gate 4: actions_taken[], remaining_missing[].
const r = $input.first().json;
const actions_taken = r.provisioned.map(p => `Auto-provisioned or attempted: ${p.name}`).concat(r.manual.map(m => `Request package generated: ${m.name}`));
const remaining_missing = r.manual.map(m => m.name);
return [{ json: {
  timestamp: new Date().toISOString(),
  actions_taken,
  remaining_missing,
  total_missing: r.total_missing,
  provisioned: r.provisioned.map(p => ({ name: p.name, method: p.method, stored_in: p.stored_in || 'n/a' })),
  manual: r.manual.map(m => ({ name: m.name, reason: m.reason })),
  errors: r.errors || [],
  request_packages: r.request_packages || []
} }];
